class CartService:
    CART_SESSION_KEY = 'cart'

    @staticmethod
    def get_cart(request):
        if CartService.CART_SESSION_KEY not in request.session:
            request.session[CartService.CART_SESSION_KEY] = {}
        return request.session[CartService.CART_SESSION_KEY]

    @staticmethod
    def add_to_cart(request, barco_id, cantidad):
        cart = CartService.get_cart(request)
        barco_id_str = str(barco_id)

        if barco_id_str in cart:
            cart[barco_id_str]['cantidad'] += cantidad
        else:
            barco = Barco.objects.get(id=barco_id)
            cart[barco_id_str] = {
                'nombre': barco.nombre,
                'precio_dia': str(barco.precio_dia),
                'cantidad': cantidad,
                'disponibilidad': barco.disponibilidad,
            }

        request.session[CartService.CART_SESSION_KEY] = cart
        request.session.modified = True

    @staticmethod
    def update_cart(request, barco_id, cantidad):
        cart = CartService.get_cart(request)
        barco_id_str = str(barco_id)

        if barco_id_str in cart:
            if cantidad <= 0:
                del cart[barco_id_str]
            else:
                cart[barco_id_str]['cantidad'] = cantidad

        request.session[CartService.CART_SESSION_KEY] = cart
        request.session.modified = True

    @staticmethod
    def clear_cart(request):
        request.session[CartService.CART_SESSION_KEY] = {}
        request.session.modified = True

    @staticmethod
    def get_cart_items(request):
        cart = CartService.get_cart(request)
        items = []
        for barco_id, item in cart.items():
            try:
                barco = Barco.objects.get(id=int(barco_id))
                items.append({
                    'barco': barco,
                    'cantidad': item['cantidad'],
                    'precio_dia': Decimal(item['precio_dia']),
                    'subtotal': Decimal(item['precio_dia']) * item['cantidad'],
                })
            except Barco.DoesNotExist:
                pass
        return items

    @staticmethod
    def get_cart_total(request):
        items = CartService.get_cart_items(request)
        total = sum(item['subtotal'] for item in items)
        return total

from django.shortcuts import render, redirect
from django.views import View
from django.http import JsonResponse
from django.views.decorators.http import require_http_methods
from django.utils.decorators import method_decorator
from .services import CartService
from catalog.models import Barco
from django.contrib import messages


class CartView(View):
    def get(self, request):
        items = CartService.get_cart_items(request)
        total = CartService.get_cart_total(request)
        return render(request, 'cart/view.html', {
            'items': items,
            'total': total,
        })


class AddToCartView(View):
    def post(self, request):
        barco_id = request.POST.get('barco_id')
        cantidad = request.POST.get('cantidad', 1)

        try:
            barco_id = int(barco_id)
            cantidad = int(cantidad)

            if cantidad <= 0:
                messages.error(request, 'La cantidad debe ser mayor a 0.')
                return redirect('catalog:barco_detail', id=barco_id)

            barco = Barco.objects.get(id=barco_id, activo=True)

            if cantidad > barco.disponibilidad:
                messages.error(request, f'Solo hay {barco.disponibilidad} unidades disponibles.')
                return redirect('catalog:barco_detail', id=barco_id)

            CartService.add_to_cart(request, barco_id, cantidad)
            messages.success(request, f'{barco.nombre} añadido a la cesta.')
            return redirect('cart:view')
        except (ValueError, Barco.DoesNotExist):
            messages.error(request, 'Error al añadir el barco a la cesta.')
            return redirect('catalog:barco_list')


class UpdateCartView(View):
    def post(self, request):
        barco_id = request.POST.get('barco_id')
        cantidad = request.POST.get('cantidad', 0)

        try:
            barco_id = int(barco_id)
            cantidad = int(cantidad)
            CartService.update_cart(request, barco_id, cantidad)
            messages.success(request, 'Cesta actualizada.')
        except (ValueError, TypeError):
            messages.error(request, 'Error al actualizar la cesta.')

        return redirect('cart:view')


class ClearCartView(View):
    def post(self, request):
        CartService.clear_cart(request)
        messages.success(request, 'Cesta vaciada.')
        return redirect('cart:view')

