{% block title %}Registro - Hundidos{% endblock %}

{% block content %}
<div class="container mt-5">
    <div class="row justify-content-center">
        <div class="col-md-6">
            <div class="card">
                <div class="card-body">
                    <h2 class="card-title text-center mb-4">Registro de Cliente</h2>
                    <form method="post">
                        {% csrf_token %}
                        <div class="mb-3">
                            <label for="{{ form.email.id_for_label }}" class="form-label">Correo Electrónico:</label>
                            {{ form.email }}
                            {% if form.email.errors %}
                                <div class="alert alert-danger mt-2">{{ form.email.errors }}</div>
                            {% endif %}
                        </div>
                        <div class="mb-3">
                            <label for="{{ form.password1.id_for_label }}" class="form-label">Contraseña:</label>
                            {{ form.password1 }}
                            {% if form.password1.errors %}
                                <div class="alert alert-danger mt-2">{{ form.password1.errors }}</div>
                            {% endif %}
                        </div>
                        <div class="mb-3">
                            <label for="{{ form.password2.id_for_label }}" class="form-label">Confirmar Contraseña:</label>
                            {{ form.password2 }}
                            {% if form.password2.errors %}
                                <div class="alert alert-danger mt-2">{{ form.password2.errors }}</div>
                            {% endif %}
                        </div>
                        {% if form.non_field_errors %}
                            <div class="alert alert-danger">{{ form.non_field_errors }}</div>
                        {% endif %}
                        <button type="submit" class="btn btn-primary w-100">Registrarse</button>
                    </form>
                    <p class="text-center mt-3">
                        ¿Ya tienes cuenta? <a href="{% url 'accounts:login' %}">Inicia sesión aquí</a>
                    </p>
                </div>
            </div>
        </div>
